// // This module calculates the quotient and remainder of two 2-bit numbers. If the divisor is zero, it returns 11 for both quotient and remainder.
module Divider2Bit (  
    input [1:0] dividend,  
    input [1:0] divisor,  
    output reg [1:0] quotient,  
    output reg [1:0] remainder  
);  
    always @(*) begin  
        if (divisor == 2'b00) begin  
            quotient = 2'b00;  
            remainder = 2'b00;  
        end else begin  
            quotient = dividend / divisor;  
            remainder = dividend % divisor;  
        end  
    end  
endmodule
